49	function buildOutputField(field: DMMF.SchemaField) {
50	  let fieldType: ts.TypeBuilder
51	
52	  if (field.outputType.location === 'enumTypes' && field.outputType.namespace === 'model') {
53	    fieldType = ts.namedType(enumTypeName(field.outputType))
54	  } else {
55	    const typeNames = GraphQLScalarToJSTypeTable[field.outputType.type] ?? field.outputType.type
56	    fieldType = Array.isArray(typeNames) ? ts.namedType(typeNames[0]) : ts.namedType(typeNames)
57	  }
58	
59	  if (field.outputType.isList) {
60	    fieldType = ts.array(fieldType)
61	  } else if (field.isNullable) {
62	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
63	  }
64	
65	  const property = ts.property(field.name, fieldType)
66	  if (field.deprecation) {
67	    property.setDocComment(
68	      ts.docComment(`@deprecated since ${field.deprecation.sinceVersion} because ${field.deprecation.reason}`),
69	    )
70	  }
71	
72	  return property
73	}
