### Model Iteration Pattern: TSClient

**`packages/client-generator-js/src/TSClient/TSClient.ts`** is the core class that transforms DMMF into TypeScript:

```typescript
export class TSClient implements Generable {
  protected readonly dmmf: DMMFHelper

  constructor(protected readonly options: TSClientOptions) {
    this.dmmf = new DMMFHelper(options.dmmf)
  }

  public toTS(): string {
    const context = new GenerateContext({
      dmmf: this.dmmf,
      generator: this.options.generator,
      provider: this.options.activeProvider,
    })

    // Key pattern: iterate over models and create a Model instance for each
    const modelAndTypes = Object.values(this.dmmf.typeAndModelMap).reduce((acc, modelOrType) => {
      if (this.dmmf.outputTypeMap.model[modelOrType.name]) {
        acc.push(new Model(modelOrType, context))  // Wrap each DMMF model
      }
      return acc
    }, [] as Model[])

    // Generate enums
    const prismaEnums = this.dmmf.schema.enumTypes.prisma?.map(
      (type) => new Enum(type, true).toTS()
    )

    const modelEnums: string[] = []
    for (const datamodelEnum of this.dmmf.datamodel.enums) {
      modelEnums.push(new Enum(datamodelEnumToSchemaEnum(datamodelEnum), false).toTS())
    }

    // Gather all type definitions
    const typeStrings = [
      ...commonCodeTS(this.options),
      ...modelAndTypes.map(m => m.toTS()),
      ...prismaEnums,
      ...modelEnums,
      // ... more type generation
    ]

    return typeStrings.join('\n')
  }
}
```

### The Generable Pattern

Every code-generating class implements **`Generable`**:

**`packages/client-generator-js/src/TSClient/Generable.ts`**:
```typescript
export interface Generable {
  toJS?(): string      // Generate JavaScript runtime code
  toTS(): string       // Generate TypeScript type definitions
  toBrowserJS?(): string
  toTSWithoutNamespace?(): string
}

// Helper functions to extract generated code
export function JS(gen: Generable): string { return gen.toJS?.() ?? '' }
export function TS(gen: Generable): string { return gen.toTS() }
export function BrowserJS(gen: Generable): string { return gen.toBrowserJS?.() ?? '' }
```

### Model Wrapper Pattern

**`packages/client-generator-js/src/TSClient/Model.ts`** shows how individual models are generated:

```typescript
export class Model implements Generable {
  protected type: DMMF.OutputType
  protected mapping?: DMMF.ModelMapping

  constructor(
    protected readonly model: DMMF.Model,  // The DMMF model
    protected readonly context: GenerateContext,
  ) {
    this.dmmf = context.dmmf
    this.type = this.context.dmmf.outputTypeMap.model[model.name]
    this.mapping = this.context.dmmf.mappings.modelOperations.find(
      (m) => m.model === model.name
    )!
  }

  protected get argsTypes(): ts.Export<ts.TypeDeclaration>[] {
    const argsTypes: ts.Export<ts.TypeDeclaration>[] = []

    // Iterate over all DMMF model actions (findMany, create, update, delete, etc.)
    for (const action of Object.keys(DMMF.ModelAction)) {
      const fieldName = this.rootFieldNameForAction(action as DMMF.ModelAction)
      if (!fieldName) continue

      const field = this.dmmf.rootFieldMap[fieldName]
      if (!field) throw new Error(`Could not find field ${fieldName}`)

      // Generate args types for each action
      argsTypes.push(
        new ArgsTypeBuilder(this.type, this.context, action as DMMF.ModelAction)
          .addSelectArg()
          .addIncludeArgIfHasRelations()
          .addSchemaArgs(field.args)
          .createExport(),
      )
    }

    // Generate field args for fields with nested operations
    for (const field of this.type.fields) {
      if (!field.args.length) continue
      const fieldOutput = this.dmmf.resolveOutputObjectType(field.outputType)
      if (!fieldOutput) continue

      argsTypes.push(
        new ArgsTypeBuilder(fieldOutput, this.context)
          .addSelectArg()
          .addIncludeArgIfHasRelations()
          .addSchemaArgs(field.args)
          .setGeneratedName(getModelFieldArgsName(field, this.model.name))
          .createExport(),
      )
    }

    return argsTypes
  }

  public toTS(): string {
    // Return the complete TypeScript type definitions for this model
    return ts.stringify(ts.moduleExport(...allTypes))
  }
}
```

### Key Pattern: Building Output Types

**`packages/client-generator-js/src/TSClient/Output.ts`** shows how model fields are converted to TypeScript types:

```typescript
export function buildModelOutputProperty(field: DMMF.Field, dmmf: DMMFHelper) {
  // Determine the TypeScript type for this field
  let fieldTypeName = GraphQLScalarToJSTypeTable[field.type] ?? field.type

  let fieldType: ts.TypeBuilder

  if (field.kind === 'object') {
    // Relation to another model
    const payloadType = ts.namedType(getPayloadName(field.type))
    fieldType = payloadType
  } else if (field.kind === 'enum') {
    // Enum field
    fieldType = ts.namedType(`$Enums.${fieldTypeName}`)
  } else {
    // Scalar (String, Int, Boolean, DateTime, etc.)
    fieldType = ts.namedType(fieldTypeName)
  }

  // Handle list and nullable modifiers
  if (field.isList) {
    fieldType = ts.array(fieldType)
  } else if (!field.isRequired) {
    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)  // Type | null
  }

  const property = ts.property(field.name, fieldType)
  if (field.documentation) {
    property.setDocComment(ts.docComment(field.documentation))
  }
  return property
}
```

### Generation Flow Summary

1. Generator receives `DMMF.Document` as input
2. **DMMFHelper** wraps it for convenient access
3. **TSClient** orchestrates the generation:
   - Iterates `dmmf.datamodel.models` → creates `Model` instance for each
   - Iterates `dmmf.datamodel.enums` → creates `Enum` instance for each
   - Iterates `dmmf.schema` structures for operations and types
4. Each **Model** (implementing `Generable`):
   - Accesses its fields via `model.fields`
   - Checks field `kind` to determine handling (scalar, object, enum)
   - Generates args types for each available action (findMany, create, update, etc.)
   - Builds TypeScript types for select/include/where arguments
5. All generated code collected into a **FileMap**:
   ```typescript
   interface FileMap {
     [name: string]: string | FileMap
   }
   // Example: { 'index.d.ts': '...', 'index.js': '...', 'package.json': '...' }
   ```
6. **Files written** to output directory with proper structure and exports

