import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClientClass } from './codegen/generate-client-class'
import { generateEnums } from './codegen/generate-enums'
import { generateInputTypes } from './codegen/generate-input-types'
import { generateModelInterfaces } from './codegen/generate-model-interfaces'

export type GenerateOptions = {
  dmmf: DMMF.Document
  outputDir: string
}

/** Generates all REST API client files from DMMF and writes them to outputDir. */
export async function generate(options: GenerateOptions): Promise<void> {
  const { dmmf, outputDir } = options
  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums

  await fs.mkdir(outputDir, { recursive: true })

  const enumsContent = generateEnums(enums)
  if (enumsContent) {
    await fs.writeFile(path.join(outputDir, 'enums.ts'), enumsContent, 'utf-8')
  }

  const modelsContent = generateModelInterfaces(models, enums)
  await fs.writeFile(path.join(outputDir, 'models.ts'), modelsContent, 'utf-8')

  const inputsContent = generateInputTypes(models, enums)
  await fs.writeFile(path.join(outputDir, 'inputs.ts'), inputsContent, 'utf-8')

  const clientContent = generateClientClass(models)
  await fs.writeFile(path.join(outputDir, 'client.ts'), clientContent, 'utf-8')

  const indexContent = generateIndex(enums.length > 0)
  await fs.writeFile(path.join(outputDir, 'index.ts'), indexContent, 'utf-8')
}

function generateIndex(hasEnums: boolean): string {
  const lines = ['// Generated by @prisma/generator-rest-api — do not edit', '']
  if (hasEnums) {
    lines.push("export * from './enums'")
  }
  lines.push("export * from './models'", "export * from './inputs'", "export * from './client'", '')
  return lines.join('\n')
}

