import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateModelInterfaces } from '../../src/codegen/generate-model-interfaces'

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as DMMF.Model
}

describe('generateModelInterfaces', () => {
  test('generates interface for a simple model', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'email', type: 'String' }),
    ])
    const result = generateModelInterfaces([model], [])
    expect(result).toContain('export interface User {')
    expect(result).toContain('  id: number')
    expect(result).toContain('  email: string')
  })

  test('excludes relation fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true }),
    ])
    const result = generateModelInterfaces([model], [])
    expect(result).toContain('  id: number')
    expect(result).not.toContain('posts')
  })

  test('handles optional fields with null union', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'name', type: 'String', isRequired: false }),
    ])
    const result = generateModelInterfaces([model], [])
    expect(result).toContain('  name: string | null')
  })

  test('handles list fields', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'tags', type: 'String', isList: true }),
    ])
    const result = generateModelInterfaces([model], [])
    expect(result).toContain('  tags: string[]')
  })

  test('handles enum fields with imports', () => {
    const enumDef = { name: 'Role', values: [{ name: 'ADMIN', dbName: null }] } as DMMF.DatamodelEnum
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    ])
    const result = generateModelInterfaces([model], [enumDef])
    expect(result).toContain("import type { Role } from './enums'")
    expect(result).toContain('  role: Role')
  })

  test('includes JsonValue type when Json field is present', () => {
    const model = makeModel('User', [
      makeField({ name: 'id', type: 'Int', isId: true }),
      makeField({ name: 'data', type: 'Json' }),
    ])
    const result = generateModelInterfaces([model], [])
    expect(result).toContain('export type JsonValue')
    expect(result).toContain('  data: JsonValue')
  })

  test('generates multiple models', () => {
    const user = makeModel('User', [makeField({ name: 'id', type: 'Int', isId: true })])
    const post = makeModel('Post', [makeField({ name: 'id', type: 'Int', isId: true })])
    const result = generateModelInterfaces([user, post], [])
    expect(result).toContain('export interface User {')
    expect(result).toContain('export interface Post {')
  })
})

