import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateClientClass } from '../../src/codegen/generate-client-class'

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as DMMF.Model
}

describe('generateClientClass', () => {
  const userModel = makeModel('User', [
    makeField({ name: 'id', type: 'Int', isId: true }),
    makeField({ name: 'email', type: 'String' }),
  ])

  test('generates RestApiClient class', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('export class RestApiClient {')
  })

  test('generates imports for models and input types', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain("import type { User } from './models'")
    expect(result).toContain("import type { UserCreateInput, UserUpdateInput, UserWhereUniqueInput } from './inputs'")
  })

  test('generates FindManyParams interface', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('export interface FindManyParams<T> {')
  })

  test('generates findMany method', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('async userFindMany(params?: FindManyParams<User>): Promise<User[]>')
  })

  test('generates findUnique method', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain(
      'async userFindUnique(params: { where: UserWhereUniqueInput }): Promise<User | null>',
    )
  })

  test('generates create method', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('async userCreate(params: { data: UserCreateInput }): Promise<User>')
  })

  test('generates update method', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain(
      'async userUpdate(params: { where: UserWhereUniqueInput; data: UserUpdateInput }): Promise<User>',
    )
  })

  test('generates delete method', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('async userDelete(params: { where: UserWhereUniqueInput }): Promise<User>')
  })

  test('generates methods for multiple models', () => {
    const postModel = makeModel('Post', [makeField({ name: 'id', type: 'Int', isId: true })])
    const result = generateClientClass([userModel, postModel])
    expect(result).toContain('async userFindMany')
    expect(result).toContain('async postFindMany')
    expect(result).toContain('async userCreate')
    expect(result).toContain('async postCreate')
  })

  test('uses lowercase model name for method prefix', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('async userFindMany')
    expect(result).not.toContain('async UserFindMany')
  })

  test('uses private fields with # syntax', () => {
    const result = generateClientClass([userModel])
    expect(result).toContain('#baseUrl')
    expect(result).toContain('#headers')
    expect(result).toContain('#request')
    expect(result).toContain('#toQueryString')
  })
})

