    expect(inputsContent).toContain('export interface UserUpdateInput {')
    expect(inputsContent).toContain('export interface UserWhereUniqueInput {')

    const clientContent = fs.readFileSync(path.join(outputDir, 'client.ts'), 'utf-8')
    expect(clientContent).toContain('export class RestApiClient {')
    expect(clientContent).toContain('async userFindMany')
    expect(clientContent).toContain('async userCreate')

    generator.stop()
  })

  test('schema with relations excludes relation fields from interfaces', async () => {
    const generator = await getGenerator({
      schemaPath: path.join(__dirname, 'fixtures/relations.prisma'),
      printDownloadProgress: false,
      skipDownload: true,
      registry,
    })

    await generator.generate()
    const outputDir = parseEnvValue(generator.options!.generator.output!)
    generatedDirs.push(outputDir)

    const modelsContent = fs.readFileSync(path.join(outputDir, 'models.ts'), 'utf-8')

    // Post should include authorId (scalar FK) but not author (relation)
    const postBlock = modelsContent.split('export interface Post {')[1].split('}')[0]
    expect(postBlock).toContain('authorId: number')
    expect(postBlock).not.toContain('author:')

    // User should not include posts (relation)
    const userBlock = modelsContent.split('export interface User {')[1].split('}')[0]
    expect(userBlock).not.toContain('posts')

    // Client should have methods for both models
    const clientContent = fs.readFileSync(path.join(outputDir, 'client.ts'), 'utf-8')
    expect(clientContent).toContain('async userFindMany')
    expect(clientContent).toContain('async postFindMany')

    generator.stop()
  })

  test('schema with enums generates enum types', async () => {
    const generator = await getGenerator({
      schemaPath: path.join(__dirname, 'fixtures/enums.prisma'),
      printDownloadProgress: false,
      skipDownload: true,
      registry,
    })

    await generator.generate()
    const outputDir = parseEnvValue(generator.options!.generator.output!)
    generatedDirs.push(outputDir)

    expect(fs.existsSync(path.join(outputDir, 'enums.ts'))).toBe(true)
    const enumsContent = fs.readFileSync(path.join(outputDir, 'enums.ts'), 'utf-8')
    expect(enumsContent).toContain("export type Role = 'ADMIN' | 'USER' | 'MODERATOR'")

    const modelsContent = fs.readFileSync(path.join(outputDir, 'models.ts'), 'utf-8')
    expect(modelsContent).toContain("import type { Role } from './enums'")
    expect(modelsContent).toContain('role: Role')

    const indexContent = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(indexContent).toContain("export * from './enums'")

    generator.stop()
  })

  test('complex schema handles @updatedAt and @default(now()) correctly', async () => {
    const generator = await getGenerator({
      schemaPath: path.join(__dirname, 'fixtures/complex.prisma'),
      printDownloadProgress: false,
      skipDownload: true,
      registry,
    })

    await generator.generate()
    const outputDir = parseEnvValue(generator.options!.generator.output!)
    generatedDirs.push(outputDir)

    const inputsContent = fs.readFileSync(path.join(outputDir, 'inputs.ts'), 'utf-8')

    // UserCreateInput should not include updatedAt (@updatedAt) or id (@id @default)
    const createBlock = inputsContent.split('export interface UserCreateInput {')[1].split('}')[0]
    expect(createBlock).not.toContain('updatedAt')
    expect(createBlock).not.toContain('  id')
    // createdAt has @default(now()), should be optional
    expect(createBlock).toContain('createdAt?: Date')
    // email is required, no default
    expect(createBlock).toContain('email: string')

    generator.stop()
  })
})

